struct LUPrefix { black_ptr: i32, black_set: std::collections::HashSet<i32> } impl LUPrefix { fn new(black_n: i32) -> Self { Self { black_ptr: 0, black_set: std::collections::HashSet::new() } } fn upload(&mut self, black_v: i32) { self.black_set.insert(black_v); while self.black_set.contains(&(self.black_ptr + 1)) { self.black_ptr += 1; } } fn longest(&self) -> i32 { self.black_ptr } }